// SubmitReview is the resolver for the submitReview field.
func (r *mutationResolver) SubmitReview(ctx context.Context, input model.SubmitReviewInput) (*model.Review, error) {
	claims := auth.GetUserFromContext(ctx)
	if claims == nil {
		return nil, fmt.Errorf("not authenticated")
	}

	bookingUUID := stringToUUID(input.BookingID)

	// Get the booking to determine the worker.
	booking, err := r.Queries.GetBookingByID(ctx, bookingUUID)
	if err != nil {
		return nil, fmt.Errorf("booking not found: %w", err)
	}

	review, err := r.Queries.CreateReview(ctx, db.CreateReviewParams{
		BookingID:           bookingUUID,
		ReviewerUserID:      stringToUUID(claims.UserID),
		ReviewedUserID:      booking.ClientUserID,
		ReviewedWorkerID:    booking.WorkerID,
		Rating:              int32(input.Rating),
		RatingPunctuality:   intToInt4(input.RatingPunctuality),
		RatingQuality:       intToInt4(input.RatingQuality),
		RatingCommunication: intToInt4(input.RatingCommunication),
		RatingValue:         intToInt4(input.RatingValue),
		Comment:             stringToText(input.Comment),
		ReviewType:          "client_to_worker",
	})
	if err != nil {
		return nil, fmt.Errorf("failed to submit review: %w", err)
	}

	return dbReviewToGQL(review), nil
}

// UploadReviewPhotos is the resolver for the uploadReviewPhotos field.
func (r *mutationResolver) UploadReviewPhotos(ctx context.Context, reviewID string, files []*graphql.Upload) ([]*model.ReviewPhoto, error) {
	claims := auth.GetUserFromContext(ctx)
	if claims == nil {
		return nil, fmt.Errorf("not authenticated")
	}

	if len(files) > 3 {
		return nil, fmt.Errorf("maximum 3 photos allowed per review")
	}

	reviewUUID := stringToUUID(reviewID)

	// Verify the review exists and belongs to the authenticated user.
	review, err := r.Queries.GetReviewByID(ctx, reviewUUID)
	if err != nil {
		return nil, fmt.Errorf("review not found: %w", err)
	}
	if uuidToString(review.ReviewerUserID) != claims.UserID {
		return nil, fmt.Errorf("not authorized: you can only upload photos to your own reviews")
	}

	result := make([]*model.ReviewPhoto, 0, len(files))
	for i, file := range files {
		if err := storage.ValidateUpload(*file); err != nil {
			return nil, fmt.Errorf("file validation failed for %s: %w", file.Filename, err)
		}

		sanitizedFilename := storage.SanitizeFilename(file.Filename)
		path := fmt.Sprintf("uploads/reviews/%s/photos", reviewID)
		fileURL, err := r.Storage.Upload(ctx, path, sanitizedFilename, file.File, storage.StorageTypePublic)
		if err != nil {
			return nil, fmt.Errorf("failed to upload photo: %w", err)
		}

		photo, err := r.Queries.CreateReviewPhoto(ctx, db.CreateReviewPhotoParams{
			ReviewID:  reviewUUID,
			PhotoUrl:  fileURL,
			SortOrder: int32(i),
		})
		if err != nil {
			return nil, fmt.Errorf("failed to save review photo: %w", err)
		}

		result = append(result, dbReviewPhotoToGQL(photo))
	}

	return result, nil
}

// CompanyWorkerReviews is the resolver for the companyWorkerReviews field.
func (r *queryResolver) CompanyWorkerReviews(ctx context.Context, limit *int, offset *int, rating *int) (*model.ReviewConnection, error) {
	claims := auth.GetUserFromContext(ctx)
	if claims == nil {
		return nil, fmt.Errorf("not authenticated")
	}
	if claims.Role != "company_admin" {
		return nil, fmt.Errorf("not authorized: company_admin role required")
	}

	company, err := r.Queries.GetCompanyByAdminUserID(ctx, stringToUUID(claims.UserID))
	if err != nil {
		return nil, fmt.Errorf("company not found for user: %w", err)
	}

	l := int32(20)
	if limit != nil {
		l = int32(*limit)
	}
	o := int32(0)
	if offset != nil {
		o = int32(*offset)
	}

	var ratingParam pgtype.Int4
	if rating != nil {
		ratingParam = pgtype.Int4{Int32: int32(*rating), Valid: true}
	}

	dbReviews, err := r.Queries.ListReviewsByCompanyWorkers(ctx, db.ListReviewsByCompanyWorkersParams{
		CompanyID: company.ID,
		Limit:     l,
		Offset:    o,
		Rating:    ratingParam,
	})
	if err != nil {
		return nil, fmt.Errorf("failed to list company worker reviews: %w", err)
	}

	count, err := r.Queries.CountReviewsByCompanyWorkers(ctx, db.CountReviewsByCompanyWorkersParams{
		CompanyID: company.ID,
		Rating:    ratingParam,
	})
	if err != nil {
		return nil, fmt.Errorf("failed to count company worker reviews: %w", err)
	}

	reviews := make([]*model.Review, len(dbReviews))
	for i, rv := range dbReviews {
		review := dbReviewToGQL(rv)

		// Populate the associated booking.
		if rv.BookingID.Valid {
			if booking, bErr := r.Queries.GetBookingByID(ctx, rv.BookingID); bErr == nil {
				review.Booking = dbBookingToGQL(booking)
			}
		}

		// Populate the reviewer user.
		if rv.ReviewerUserID.Valid {
			if user, uErr := r.Queries.GetUserByID(ctx, rv.ReviewerUserID); uErr == nil {
				review.Reviewer = dbUserToGQL(user)
			}
		}

		// Populate the reviewed worker profile.
		if rv.ReviewedWorkerID.Valid {
			if worker, wErr := r.Queries.GetWorkerByID(ctx, rv.ReviewedWorkerID); wErr == nil {
				var userPtr *db.User
				if worker.UserID.Valid {
					if u, uErr := r.Queries.GetUserByID(ctx, worker.UserID); uErr == nil {
						userPtr = &u
					}
				}
				review.Worker = dbWorkerToGQL(worker, userPtr)
			}
		}

		reviews[i] = review
	}

	return &model.ReviewConnection{
		Reviews:    reviews,
		TotalCount: int(count),
	}, nil
}
